SELECT
	member_chnl_id
FROM
	TB_MEMBER_CHNL

	AND character_no = #{characterNo}
	AND member_no = #{memberNo}

		AND member_chnl_id != #{excludeChannelId}


ORDER BY member_chnl_sn ASC

	LIMIT #{pageable.offset}, #{pageable.pageSize}

SELECT C.member_chnl_id AS memberChannelId, C.member_chnl_nm AS memberChannelName, C.member_chnl_sn AS channelPriority, C.pin_type AS pinType, C.pin_type_id AS pinTypeId, C.album_id AS albumId, IFNULL(C.track_cnt, 0) AS trackCount, IFNULL(C.chnl_play_tm, 0) AS channelPlayTime, C.create_dtime AS createDateTime, C.update_dtime AS updateDateTime, D.ALBUM_IMG_SIZE AS size, D.album_img_url AS url, D.update_dtime AS albumImgUpdateDateTime, E.TITLE AS albumTitle FROM TB_MEMBER_CHNL AS C LEFT JOIN TB_ALBUM_IMG D ON C.ALBUM_ID = D.ALBUM_ID LEFT JOIN TED_ALBUM E ON C.ALBUM_ID = E.ALBUM_ID WHERE C.member_chnl_id IN
#{channelId}
ORDER BY channelPriority ASC

SELECT
COUNT(member_chnl_id)
FROM
tb_member_chnl

	AND character_no = #{characterNo}
	AND member_no = #{memberNo}

SELECT
	COUNT(member_chnl_id)
FROM
	TB_MEMBER_CHNL

	AND character_no = #{characterNo}
	AND member_no = #{memberNo}

SELECT
	count(*)
FROM
	tb_member_chnl
WHERE character_no = #{characterNo}
AND member_no = #{memberNo}
AND member_chnl_nm = #{channelName}

SELECT
	member_chnl_nm
FROM
	tb_member_chnl
WHERE character_no = #{characterNo}
AND member_no = #{memberNo}
AND member_chnl_nm like #{channelName}

